def _parse_eurostat(json_str: str) -> dict[int, int]:
    data = json.loads(json_str)
    value = data['value']
    age_index = data['dimension']['age']['category']['index']
    result = {}
    for label, pos in age_index.items():
        if label == 'Y_LT1':
            age = 0
        elif label.startswith('Y') and label[1:].isdigit():
            age = int(label[1:])
        else:
            continue
        result[age] = value.get(str(pos), 0)
    return result


_MALE = _parse_eurostat(_MALE_JSON)
_FEMALE = _parse_eurostat(_FEMALE_JSON)

MODEL = PopulationModel(
    groups={
        **{Category(sex=Sex.FEMALE, age=age): pop for age, pop in _FEMALE.items()},
        **{Category(sex=Sex.MALE,   age=age): pop for age, pop in _MALE.items()},
    }
)
